116	#[must_use]
117	pub fn resolve_model_alias(model: &str) -> String {
118	    let trimmed = model.trim();
119	    let lower = trimmed.to_ascii_lowercase();
120	    MODEL_REGISTRY
121	        .iter()
122	        .find_map(|(alias, metadata)| {
123	            (*alias == lower).then_some(match metadata.provider {
124	                ProviderKind::Anthropic => match *alias {
125	                    "opus" => "claude-opus-4-6",
126	                    "sonnet" => "claude-sonnet-4-6",
127	                    "haiku" => "claude-haiku-4-5-20251213",
128	                    _ => trimmed,
129	                },
130	                ProviderKind::Xai => match *alias {
131	                    "grok" | "grok-3" => "grok-3",
132	                    "grok-mini" | "grok-3-mini" => "grok-3-mini",
133	                    "grok-2" => "grok-2",
134	                    _ => trimmed,
135	                },
136	                ProviderKind::OpenAi => trimmed,
137	            })
138	        })
139	        .map_or_else(|| trimmed.to_string(), ToOwned::to_owned)
140	}
