164	#[must_use]
165	pub fn detect_provider_kind(model: &str) -> ProviderKind {
166	    if let Some(metadata) = metadata_for_model(model) {
167	        return metadata.provider;
168	    }
169	    if anthropic::has_auth_from_env_or_saved().unwrap_or(false) {
170	        return ProviderKind::Anthropic;
171	    }
172	    if openai_compat::has_api_key("OPENAI_API_KEY") {
173	        return ProviderKind::OpenAi;
174	    }
175	    if openai_compat::has_api_key("XAI_API_KEY") {
