461	    async fn send_raw_request(
462	        &self,
463	        request: &MessageRequest,
464	    ) -> Result<reqwest::Response, ApiError> {
465	        let request_url = format!("{}/v1/messages", self.base_url.trim_end_matches('/'));
466	        let request_builder = self
467	            .http
468	            .post(&request_url)
469	            .header("content-type", "application/json");
470	        let mut request_builder = self.auth.apply(request_builder);
471	        for (header_name, header_value) in self.request_profile.header_pairs() {
472	            request_builder = request_builder.header(header_name, header_value);
473	        }
474	
475	        let request_body = self.request_profile.render_json_body(request)?;
476	        if std::env::var("CLAW_LOG_API").is_ok() {
477	            let mut log_body = request_body.clone();
478	            if let Some(tools) = log_body.get("tools").and_then(|t| t.as_array()) {
479	                let names: Vec<String> = tools
480	                    .iter()
481	                    .filter_map(|t| t.get("name").and_then(|n| n.as_str()).map(String::from))
482	                    .collect();
483	                let summary = serde_json::json!({
484	                    "count": names.len(),
485	                    "names": names,
486	                });
487	                if let Some(obj) = log_body.as_object_mut() {
