504	    fn record_request_failure(&self, attempt: u32, error: &ApiError) {
505	        if let Some(session_tracer) = &self.session_tracer {
506	            session_tracer.record_http_request_failed(
507	                attempt,
508	                "POST",
509	                "/v1/messages",
510	                error.to_string(),
511	                error.is_retryable(),
512	                Map::new(),
