524	    fn backoff_for_attempt(&self, attempt: u32) -> Result<Duration, ApiError> {
525	        let Some(multiplier) = 1_u32.checked_shl(attempt.saturating_sub(1)) else {
526	            return Err(ApiError::BackoffOverflow {
527	                attempt,
528	                base_delay: self.initial_backoff,
529	            });
530	        };
531	        Ok(self
532	            .initial_backoff
533	            .checked_mul(multiplier)
534	            .map_or(self.max_backoff, |delay| delay.min(self.max_backoff)))
535	    }
536	}
