593	pub fn resolve_startup_auth_source<F>(load_oauth_config: F) -> Result<AuthSource, ApiError>
594	where
595	    F: FnOnce() -> Result<Option<OAuthConfig>, ApiError>,
596	{
597	    if let Some(api_key) = read_env_non_empty("ANTHROPIC_API_KEY")? {
598	        return match read_env_non_empty("ANTHROPIC_AUTH_TOKEN")? {
599	            Some(bearer_token) => Ok(AuthSource::ApiKeyAndBearer {
600	                api_key,
601	                bearer_token,
602	            }),
603	            None => Ok(AuthSource::ApiKey(api_key)),
604	        };
605	    }
606	    if let Some(bearer_token) = read_env_non_empty("ANTHROPIC_AUTH_TOKEN")? {
607	        return Ok(AuthSource::BearerToken(bearer_token));
608	    }
609	
610	    let Some(token_set) = load_saved_oauth_token()? else {
611	        return Err(ApiError::missing_credentials(
612	            "Anthropic",
613	            &["ANTHROPIC_AUTH_TOKEN", "ANTHROPIC_API_KEY"],
614	        ));
615	    };
616	    if !oauth_token_is_expired(&token_set) {
617	        return Ok(AuthSource::BearerToken(token_set.access_token));
618	    }
619	    if token_set.refresh_token.is_none() {
620	        return Err(ApiError::ExpiredOAuthToken);
621	    }
622	
623	    let Some(config) = load_oauth_config()? else {
624	        return Err(ApiError::Auth(
625	            "saved OAuth token is expired; runtime OAuth config is missing".to_string(),
626	        ));
627	    };
628	    Ok(AuthSource::from(resolve_saved_oauth_token_set(
629	        &config, token_set,
630	    )?))
631	}
632	
633	fn resolve_saved_oauth_token_set(
634	    config: &OAuthConfig,
635	    token_set: OAuthTokenSet,
636	) -> Result<OAuthTokenSet, ApiError> {
637	    if !oauth_token_is_expired(&token_set) {
638	        return Ok(token_set);
639	    }
640	    let Some(refresh_token) = token_set.refresh_token.clone() else {
641	        return Err(ApiError::ExpiredOAuthToken);
642	    };
643	    let client = AnthropicClient::from_auth(AuthSource::None).with_base_url(read_base_url());
644	    let refreshed = client_runtime_block_on(async {
645	        client
646	            .refresh_oauth_token(
647	                config,
648	                &OAuthRefreshRequest::from_config(
649	                    config,
650	                    refresh_token,
651	                    Some(token_set.scopes.clone()),
652	                ),
653	            )
654	            .await
655	    })?;
656	    let resolved = OAuthTokenSet {
657	        access_token: refreshed.access_token,
658	        refresh_token: refreshed.refresh_token.or(token_set.refresh_token),
659	        expires_at: refreshed.expires_at,
660	        scopes: refreshed.scopes,
661	    };
662	    save_oauth_credentials(&runtime::OAuthTokenSet {
663	        access_token: resolved.access_token.clone(),
664	        refresh_token: resolved.refresh_token.clone(),
665	        expires_at: resolved.expires_at,
666	        scopes: resolved.scopes.clone(),
667	    })
668	    .map_err(ApiError::from)?;
669	    Ok(resolved)
670	}
