847	async fn expect_success(response: reqwest::Response) -> Result<reqwest::Response, ApiError> {
848	    let status = response.status();
849	    if status.is_success() {
850	        return Ok(response);
851	    }
852	
853	    let body = response.text().await.unwrap_or_else(|_| String::new());
854	    let parsed_error = serde_json::from_str::<AnthropicErrorEnvelope>(&body).ok();
855	    let retryable = is_retryable_status(status);
856	
857	    Err(ApiError::Api {
858	        status,
859	        error_type: parsed_error
860	            .as_ref()
861	            .map(|error| error.error.error_type.clone()),
862	        message: parsed_error
863	            .as_ref()
864	            .map(|error| error.error.message.clone()),
865	        body,
866	        retryable,
867	    })
868	}
