941	        let listener = TcpListener::bind("127.0.0.1:0").expect("bind listener");
942	        let address = listener.local_addr().expect("local addr");
943	        thread::spawn(move || {
944	            let (mut stream, _) = listener.accept().expect("accept connection");
945	            let mut buffer = [0_u8; 4096];
946	            let _ = stream.read(&mut buffer).expect("read request");
947	            let response = format!(
948	                "HTTP/1.1 200 OK\r\ncontent-type: application/json\r\ncontent-length: {}\r\n\r\n{}",
949	                response_body.len(),
950	                response_body
951	            );
952	            stream
953	                .write_all(response.as_bytes())
954	                .expect("write response");
955	        });
956	        format!("http://{address}/oauth/token")
957	    }
