166	                Ok(response) => match expect_success(response).await {
167	                    Ok(response) => return Ok(response),
168	                    Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => error,
169	                    Err(error) => return Err(error),
170	                },
171	                Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => error,
172	                Err(error) => return Err(error),
173	            };
174	
175	            if attempts > self.max_retries {
176	                break retryable_error;
177	            }
178	
179	            tokio::time::sleep(self.backoff_for_attempt(attempts)?).await;
180	        };
181	
182	        Err(ApiError::RetriesExhausted {
183	            attempts,
184	            last_error: Box::new(last_error),
