5	#[derive(Debug)]
6	pub enum ApiError {
7	    MissingCredentials {
8	        provider: &'static str,
9	        env_vars: &'static [&'static str],
10	    },
11	    ExpiredOAuthToken,
12	    Auth(String),
13	    InvalidApiKeyEnv(VarError),
14	    Http(reqwest::Error),
15	    Io(std::io::Error),
16	    Json(serde_json::Error),
17	    Api {
18	        status: reqwest::StatusCode,
19	        error_type: Option<String>,
20	        message: Option<String>,
21	        body: String,
22	        retryable: bool,
23	    },
24	    RetriesExhausted {
25	        attempts: u32,
26	        last_error: Box<ApiError>,
27	    },
28	    InvalidSseFrame(&'static str),
29	    BackoffOverflow {
30	        attempt: u32,
31	        base_delay: Duration,
32	    },
33	}
34	
35	impl ApiError {
36	    #[must_use]
37	    pub const fn missing_credentials(
38	        provider: &'static str,
39	        env_vars: &'static [&'static str],
40	    ) -> Self {
41	        Self::MissingCredentials { provider, env_vars }
42	    }
43	
44	    #[must_use]
45	    pub fn is_retryable(&self) -> bool {
46	        match self {
47	            Self::Http(error) => error.is_connect() || error.is_timeout() || error.is_request(),
48	            Self::Api { retryable, .. } => *retryable,
49	            Self::RetriesExhausted { last_error, .. } => last_error.is_retryable(),
50	            Self::MissingCredentials { .. }
51	            | Self::ExpiredOAuthToken
52	            | Self::Auth(_)
53	            | Self::InvalidApiKeyEnv(_)
54	            | Self::Io(_)
55	            | Self::Json(_)
56	            | Self::InvalidSseFrame(_)
57	            | Self::BackoffOverflow { .. } => false,
58	        }
59	    }
60	}
61	
62	impl Display for ApiError {
63	    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
64	        match self {
65	            Self::MissingCredentials { provider, env_vars } => write!(
66	                f,
67	                "missing {provider} credentials; export {} before calling the {provider} API",
68	                env_vars.join(" or ")
69	            ),
70	            Self::ExpiredOAuthToken => {
71	                write!(
72	                    f,
73	                    "saved OAuth token is expired and no refresh token is available"
74	                )
75	            }
76	            Self::Auth(message) => write!(f, "auth error: {message}"),
77	            Self::InvalidApiKeyEnv(error) => {
78	                write!(f, "failed to read credential environment variable: {error}")
79	            }
80	            Self::Http(error) => write!(f, "http error: {error}"),
81	            Self::Io(error) => write!(f, "io error: {error}"),
82	            Self::Json(error) => write!(f, "json error: {error}"),
83	            Self::Api {
84	                status,
85	                error_type,
86	                message,
87	                body,
88	                ..
89	            } => match (error_type, message) {
90	                (Some(error_type), Some(message)) => {
91	                    write!(f, "api returned {status} ({error_type}): {message}")
92	                }
93	                _ => write!(f, "api returned {status}: {body}"),
94	            },
95	            Self::RetriesExhausted {
96	                attempts,
97	                last_error,
98	            } => write!(f, "api failed after {attempts} attempts: {last_error}"),
99	            Self::InvalidSseFrame(message) => write!(f, "invalid sse frame: {message}"),
100	            Self::BackoffOverflow {
101	                attempt,
102	                base_delay,
103	            } => write!(
104	                f,
105	                "retry backoff overflowed on attempt {attempt} with base delay {base_delay:?}"
106	            ),
107	        }
108	    }
109	}
