447	fn sanitize_path_segment(value: &str) -> String {
448	    let sanitized: String = value
449	        .chars()
450	        .map(|ch| if ch.is_ascii_alphanumeric() { ch } else { '-' })
451	        .collect();
452	    if sanitized.len() <= MAX_SANITIZED_LENGTH {
453	        return sanitized;
454	    }
455	    let suffix = format!("-{:x}", hash_string(value));
456	    format!(
457	        "{}{}",
458	        &sanitized[..MAX_SANITIZED_LENGTH.saturating_sub(suffix.len())],
459	        suffix
460	    )
461	}
